INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.414, 1, -416.5, 0.0, 190801, "2025/01/31 12:00:00", 1, 62, 1000001, "カリン", 2, 1, "2030/01/01 14:59:59", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.099, 1, -416.5, 0.0, 190801, "2025/01/31 12:00:00", 2, 62, 1000002, "カリン", 2, 1, "2030/01/01 14:59:59", "ミッションをクリアして、\n報酬をゲットしましょう！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.801, 1, -416.5, 0.0, 190801, "2025/01/31 12:00:00", 3, 63, 1000003, "カリン", 2, 1, "2030/01/01 14:59:59", "受け取ることができる\n報酬があるようです\n確認してみてください");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (0.0, 1, -416.5, 0.0, 190801, "2025/01/31 12:00:00", 4, 63, 1000004, "カリン", 2, 2, "2030/01/01 14:59:59", "報酬がもらえますよ！\nチェックしてみてください");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.12, 1, -363.0, 0.0, 190801, "2025/01/31 12:00:00", 5, 64, 1000005, "カリン", 1, 2, "2030/01/01 14:59:59", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1.68, 1, -363.0, 0.0, 190801, "2025/01/31 12:00:00", 6, 64, 1000006, "カリン", 2, 1, "2030/01/01 14:59:59", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.33, 1, -363.0, 0.0, 190801, "2025/01/31 12:00:00", 7, 64, 1000007, "カリン", 1, 2, "2030/01/01 14:59:59", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.18, 10201, -285.0, -6.0, 133701, "2025/01/31 12:00:00", 101, 61, 1020101, "ラビリスタ", 7, 3, "2030/01/01 14:59:59", "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.77, 10201, -285.0, -2.0, 133901, "2025/01/31 12:00:00", 201, 61, 1020102, "クリスティーナ", 2, 1, "2030/01/01 14:59:59", "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (15.5, 10201, -285.0, 0.0, 133801, "2025/01/31 12:00:00", 301, 61, 1020103, "ネネカ", 1, 6, "2030/01/01 14:59:59", "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9.061, 10202, -285.0, 0.0, 134301, "2025/02/28 12:00:00", 101, 61, 1020201, "ランファ", 5, 2, "2030/01/01 14:59:59", "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.699, 10202, -285.0, 0.0, 134401, "2025/02/28 12:00:00", 201, 61, 1020202, "チカ", 2, 1, "2030/01/01 14:59:59", "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.595, 10203, -285.0, 0.0, 134601, "2025/03/31 12:00:00", 101, 61, 1020301, "アオイ", 2, 1, "2030/01/01 14:59:59", "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.758, 10203, -285.0, 0.0, 134501, "2025/03/31 12:00:00", 201, 61, 1020302, "クローチェ", 2, 1, "2030/01/01 14:59:59", "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.0, 10204, -285.0, 0.0, 132302, "2025/04/30 12:00:00", 101, 61, 1020401, "ルイズマリー", 6, 2, "2030/01/01 14:59:59", "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.904, 10204, -285.0, 0.0, 132402, "2025/04/30 12:00:00", 201, 61, 1020402, "イロハ", 2, 1, "2030/01/01 14:59:59", "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.487, 10204, -285.0, 0.0, 132502, "2025/04/30 12:00:00", 301, 61, 1020403, "ソノ", 2, 4, "2030/01/01 14:59:59", "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.763, 10205, -285.0, 0.0, 134901, "2025/05/31 12:00:00", 101, 61, 1020502, "カノン", 2, 1, "2030/01/01 14:59:59", "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.417, 10205, -285.0, 0.0, 134801, "2025/05/31 12:00:00", 201, 61, 1020503, "ツムギ", 3, 1, "2030/01/01 14:59:59", "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10.335, 10206, -285.0, 0.0, 135001, "2025/06/30 12:00:00", 101, 61, 1020601, "エリス", 7, 3, "2030/01/01 14:59:59", "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.281, 10206, -285.0, 0.0, 135101, "2025/06/30 12:00:00", 201, 61, 1020602, "シェフィ", 4, 2, "2030/01/01 14:59:59", "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (12.244, 10206, -285.0, 0.0, 135201, "2025/06/30 12:00:00", 301, 61, 1020603, "プレシア", 2, 1, "2030/01/01 14:59:59", "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.339, 10207, -285.0, 0.0, 135301, "2025/07/31 12:00:00", 101, 61, 1020701, "クリア", 8, 2, "2030/01/01 14:59:59", "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.184, 10207, -285.0, 0.0, 135401, "2025/07/31 12:00:00", 201, 61, 1020702, "アネモネ", 9, 7, "2030/01/01 14:59:59", "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.906, 10208, -285.0, 0.0, 129101, "2025/08/31 12:00:00", 101, 61, 1020801, "アイラ", 2, 9, "2030/01/01 14:59:59", "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (14.465, 10208, -285.0, 0.0, 129201, "2025/08/31 12:00:00", 201, 61, 1020802, "シナツ", 2, 1, "2030/01/01 14:59:59", "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.662, 10208, -285.0, 0.0, 100101, "2025/08/31 12:00:00", 301, 61, 1020803, "ヒヨリ", 3, 4, "2030/01/01 14:59:59", "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10.915, 10208, -285.0, 0.0, 100301, "2025/08/31 12:00:00", 401, 61, 1020804, "レイ", 3, 1, "2030/01/01 14:59:59", "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.042, 10209, -285.0, 0.0, 135802, "2025/09/30 12:00:00", 101, 61, 1020901, "ユキノ", 7, 1, "2030/01/01 14:59:59", "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9.402, 10209, -285.0, 0.0, 135903, "2025/09/30 12:00:00", 201, 61, 1020902, "サツキ", 1, 4, "2030/01/01 14:59:59", "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.16, 10209, -285.0, 0.0, 136902, "2025/09/30 12:00:00", 301, 61, 1020903, "ルルィ", 1, 8, "2030/01/01 14:59:59", "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.0, 10210, -285.0, 0.0, 137401, "2025/10/31 12:00:00", 101, 61, 1021001, "カスミ", 2, 3, "2030/01/01 14:59:59", "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.12, 10210, -285.0, 0.0, 136001, "2025/10/31 12:00:00", 201, 61, 1021002, "アラクネ", 1, 4, "2030/01/01 14:59:59", "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.386, 10210, -285.0, 0.0, 136202, "2025/10/31 12:00:00", 301, 61, 1021003, "ナーナ", 2, 4, "2030/01/01 14:59:59", "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.438, 10211, -285.0, 0.0, 136402, "2025/11/30 12:00:00", 101, 61, 1021101, "ユイ", 4, 3, "2030/01/01 14:59:59", "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.35, 10211, -285.0, 0.0, 136302, "2025/11/30 12:00:00", 201, 61, 1021102, "ミソラ", 5, 1, "2030/01/01 14:59:59", "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.0, 10212, -285.0, 0.0, 136501, "2025/12/31 12:00:00", 101, 61, 1021201, "シズル", 2, 1, "2030/01/01 14:59:59", "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.25, 10212, -285.0, 0.0, 137902, "2025/12/31 12:00:00", 201, 61, 1021202, "リノ", 2, 1, "2030/01/01 14:59:59", "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.5, 10212, -285.0, 0.0, 106801, "2025/12/31 12:00:00", 301, 61, 1021203, "ラビリスタ", 2, 1, "2030/01/01 14:59:59", "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.204, 10213, -285.0, 0.0, 126501, "2026/01/31 12:00:00", 101, 61, 1021301, "ライラエル", 2, 1, "2030/01/01 14:59:59", "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.176, 10213, -285.0, 0.0, 129701, "2026/01/31 12:00:00", 201, 61, 1021302, "ネフィ＝ネラ", 2, 1, "2030/01/01 14:59:59", "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.602, 10213, -285.0, 0.0, 133101, "2026/01/31 12:00:00", 301, 61, 1021303, "ヴァイオレット", 5, 1, "2030/01/01 14:59:59", "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10.14, 10213, -285.0, 0.0, 138101, "2026/02/06 12:00:00", 102, 61, 1021304, "ライラエル", 3, 1, "2030/01/01 14:59:59", "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10.152, 10213, -285.0, 0.0, 138201, "2026/02/06 12:00:00", 202, 61, 1021305, "ネフィ＝ネラ", 7, 1, "2030/01/01 14:59:59", "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9.688, 10213, -285.0, 0.0, 138001, "2026/02/06 12:00:00", 302, 61, 1021306, "ヴァイオレット", 3, 4, "2030/01/01 14:59:59", "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.928, 10213, -285.0, 0.0, 138301, "2026/02/12 12:00:00", 401, 61, 1021307, "ペコリーヌ", 1, 2, "2030/01/01 14:59:59", "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9.19, 10214, -285.0, 0.0, 138702, "2026/02/28 12:00:00", 101, 61, 1021401, "ワカナ", 2, 4, "2030/01/01 14:59:59", "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.724, 10214, -285.0, 0.0, 138802, "2026/02/28 12:00:00", 201, 61, 1021402, "シオリ", 3, 1, "2030/01/01 14:59:59", "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.758, 10215, -285.0, 0.0, 138902, "2026/03/31 12:00:00", 101, 61, 1021501, "グレイス", 1, 4, "2030/01/01 14:59:59", "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.375, 10215, -285.0, 0.0, 139002, "2026/03/31 12:00:00", 201, 61, 1021502, "キョウカ", 4, 6, "2030/01/01 14:59:59", "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.173, 10215, -285.0, 0.0, 136902, "2026/03/31 12:00:00", 301, 61, 1021503, "ルルィ", 1, 6, "2030/01/01 14:59:59", "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.414, 2, -416.5, 0.0, 190801, "2026/04/10 12:00:00", 1, 62, 2000001, "カリン", 2, 1, "2030/01/01 14:59:59", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.099, 2, -416.5, 0.0, 190801, "2026/04/10 12:00:00", 2, 62, 2000002, "カリン", 2, 1, "2030/01/01 14:59:59", "ミッションをクリアして、\n報酬をゲットしましょう！");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.801, 2, -416.5, 0.0, 190801, "2026/04/10 12:00:00", 3, 63, 2000003, "カリン", 2, 1, "2030/01/01 14:59:59", "受け取ることができる\n報酬があるようです\n確認してみてください");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (0.0, 2, -416.5, 0.0, 190801, "2026/04/10 12:00:00", 4, 63, 2000004, "カリン", 2, 2, "2030/01/01 14:59:59", "報酬がもらえますよ！\nチェックしてみてください");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.12, 2, -363.0, 0.0, 190801, "2026/04/10 12:00:00", 5, 64, 2000005, "カリン", 1, 2, "2030/01/01 14:59:59", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1.68, 2, -363.0, 0.0, 190801, "2026/04/10 12:00:00", 6, 64, 2000006, "カリン", 2, 1, "2030/01/01 14:59:59", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.33, 2, -363.0, 0.0, 190801, "2026/04/10 12:00:00", 7, 64, 2000007, "カリン", 1, 2, "2030/01/01 14:59:59", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね");
